import{_ as a,o as r,c as o,ag as d}from"./chunks/framework.BZohXCq9.js";const q=JSON.parse('{"title":"老张餐馆 — 项目路演","description":"","frontmatter":{"title":"老张餐馆 — 项目路演","outline":[2,3]},"headers":[],"relativePath":"novels/lao-zhang-restaurant/pitch.md","filePath":"novels/lao-zhang-restaurant/pitch.md","lastUpdated":1775283989000}'),e={name:"novels/lao-zhang-restaurant/pitch.md"};function l(n,t,i,h,s,u){return r(),o("div",null,[...t[0]||(t[0]=[d('<h1 id="《老张餐馆》" tabindex="-1">《老张餐馆》 <a class="header-anchor" href="#《老张餐馆》" aria-label="Permalink to &quot;《老张餐馆》&quot;">​</a></h1><p><strong>一个被AI淘汰的程序员，回到十八线县城，接手父亲的小餐馆。</strong></p><p>这不是一个逆袭的故事。这是一个关于「明天还开门」的故事。</p><hr><h2 id="一句话" tabindex="-1">一句话 <a class="header-anchor" href="#一句话" aria-label="Permalink to &quot;一句话&quot;">​</a></h2><blockquote><p>一个人被时代扔下车之后，能不能在一碗面里找到自己？</p></blockquote><h2 id="为什么是这个故事-为什么是现在" tabindex="-1">为什么是这个故事，为什么是现在 <a class="header-anchor" href="#为什么是这个故事-为什么是现在" aria-label="Permalink to &quot;为什么是这个故事，为什么是现在&quot;">​</a></h2><p>2025年，中国有三件事同时在发生：</p><p><strong>AI正在吃掉白领的工作。</strong> 不是未来，是现在。程序员、设计师、编辑、翻译——这些曾经被认为&quot;不可替代&quot;的岗位，正在被重新定义。35岁危机变成了30岁危机，技术迭代的速度比任何一次工业革命都快。</p><p><strong>县城正在经历一场无声的裂变。</strong> 老城拆迁、新城空转、年轻人外流、老年人留守。一座县城被劈成两半——一半是崭新的商业综合体和空荡荡的电梯房，另一半是正在消亡的老街和关了门的铺面。</p><p><strong>一代人正在重新定义&quot;成功&quot;。</strong> 当&quot;大厂→买房→中产&quot;这条路断裂之后，无数人在问同一个问题：如果不做那个体面人了，我是谁？</p><p>《老张餐馆》要讲的，就是这三件事交汇处的那个人。</p><h2 id="老张是谁" tabindex="-1">老张是谁 <a class="header-anchor" href="#老张是谁" aria-label="Permalink to &quot;老张是谁&quot;">​</a></h2><p>张建国，40岁。北京某中型软件公司首席架构师，写了十五年代码。</p><p>AI编程工具越来越强。年轻人用AI一天写的代码比他一周还多。先是被从核心项目调走，然后被&quot;优化&quot;。HR让他写&quot;离职感言&quot;发内网，他一个字没写。</p><p>他有房贷、车贷、一个在北京上学的12岁儿子，和一个越来越沉默的妻子。</p><p>裁员赔偿看着不少，但算一算，撑不过半年。</p><p>老家——一个十八线小县城的老城区——父亲开了三十年的&quot;张记面馆&quot;快撑不下去了。68岁的老头腰不行了，35岁的弟弟在外面折腾了一圈赔了个精光回来帮忙，但也是个半吊子。</p><p>老张回来了。不是衣锦还乡，是走投无路。</p><p><strong>他的成长弧线：从&quot;我是来拯救这个破餐馆的&quot;到&quot;这个破餐馆拯救了我&quot;。</strong></p><h2 id="这个故事的独特性" tabindex="-1">这个故事的独特性 <a class="header-anchor" href="#这个故事的独特性" aria-label="Permalink to &quot;这个故事的独特性&quot;">​</a></h2><h3 id="餐馆是一面镜子" tabindex="-1">餐馆是一面镜子 <a class="header-anchor" href="#餐馆是一面镜子" aria-label="Permalink to &quot;餐馆是一面镜子&quot;">​</a></h3><p>餐馆是天然的叙事舞台——人来人往，每个吃饭的人都带着自己的故事。我们用一个餐馆，折射整个县城的众生相：</p><table tabindex="0"><thead><tr><th>人物</th><th>身份</th><th>折射的社会切面</th></tr></thead><tbody><tr><td>老张</td><td>被AI裁员的架构师</td><td>AI替代白领、中年失业</td></tr><tr><td>弟弟小张</td><td>在外闯荡失败回来的半吊子</td><td>教育不公平、小镇做题家的另一面</td></tr><tr><td>老老张</td><td>开了三十年店的老父亲</td><td>传统手艺的消亡与传承</td></tr><tr><td>陈胖子</td><td>拆迁暴富又返贫的食客</td><td>拆迁经济的泡沫</td></tr><tr><td>小周</td><td>每天来吃最便宜那碗面的外卖骑手</td><td>零工经济下的年轻人</td></tr><tr><td>王美兰</td><td>隔壁预制菜馆老板娘</td><td>预制菜对传统餐饮的冲击</td></tr><tr><td>赵大爷</td><td>老城区最后的钉子户</td><td>消逝中的城市记忆</td></tr><tr><td>阿明</td><td>返乡做电商的青年</td><td>返乡创业的真实困境</td></tr></tbody></table><p>每一集解决一个餐馆的具体问题（没客人、外卖平台抽成太狠、预制菜馆抢生意、城区要拆迁），同时折射一个当下的社会议题。<strong>小切口，大共鸣。</strong></p><h3 id="不是爽剧-不是苦情戏" tabindex="-1">不是爽剧，不是苦情戏 <a class="header-anchor" href="#不是爽剧-不是苦情戏" aria-label="Permalink to &quot;不是爽剧，不是苦情戏&quot;">​</a></h3><p>调性定位：<strong>温暖现实主义 + 黑色幽默 + 荒诞喜剧</strong>。</p><p>参考坐标系：</p><ul><li><strong>《漫长的季节》</strong> 的质感——小城衰败的氛围、时代碾过普通人的真实</li><li><strong>《熊家餐馆 The Bear》</strong> 的厨房戏——专业、紧凑、用食物讲人</li><li><strong>《疯狂的石头》</strong> 的荒诞——一本正经地搞笑，笑完了有点想哭</li><li><strong>《深夜食堂》</strong> 的人情味——餐馆里每个食客都是一个故事</li></ul><p><strong>绝对不做的事：</strong></p><ul><li>❌ 成功学逆袭（餐馆不会变成网红店）</li><li>❌ 主角开挂（老张会一直笨手笨脚）</li><li>❌ 卖惨催泪（苦但不惨，难但有趣）</li></ul><p><strong>一定要有的东西：</strong></p><ul><li>✅ 让人笑出来的荒诞时刻</li><li>✅ 让人突然沉默的真实瞬间</li><li>✅ 让人觉得&quot;这不就是我身边的人&quot;的角色</li></ul><h2 id="受众画像" tabindex="-1">受众画像 <a class="header-anchor" href="#受众画像" aria-label="Permalink to &quot;受众画像&quot;">​</a></h2><h3 id="核心受众-25-45岁的城市中产" tabindex="-1">核心受众：25-45岁的城市中产 <a class="header-anchor" href="#核心受众-25-45岁的城市中产" aria-label="Permalink to &quot;核心受众：25-45岁的城市中产&quot;">​</a></h3><p>他们是老张的同龄人，或者即将成为老张的人：</p><ul><li><strong>互联网/科技从业者</strong> — 最能理解AI焦虑和裁员恐惧的一群人</li><li><strong>从小城市去大城市打拼的人</strong> — 对县城有复杂的感情，既嫌弃又想念</li><li><strong>背着房贷车贷的中年人</strong> — 对&quot;体面人&quot;的坍塌感同身受</li></ul><h3 id="泛受众-所有关心-普通人怎么活-的人" tabindex="-1">泛受众：所有关心&quot;普通人怎么活&quot;的人 <a class="header-anchor" href="#泛受众-所有关心-普通人怎么活-的人" aria-label="Permalink to &quot;泛受众：所有关心&quot;普通人怎么活&quot;的人&quot;">​</a></h3><ul><li><strong>县城里的年轻人</strong> — 留守还是出走？在小周和阿明身上看到自己</li><li><strong>关注社会议题的人</strong> — AI替代、预制菜、拆迁、零工经济——每一个都是热搜级话题</li><li><strong>中国的父母辈</strong> — 老老张的倔强和沉默，是无数中国父亲的缩影</li></ul><h3 id="为什么这个受众群体足够大" tabindex="-1">为什么这个受众群体足够大？ <a class="header-anchor" href="#为什么这个受众群体足够大" aria-label="Permalink to &quot;为什么这个受众群体足够大？&quot;">​</a></h3><p>因为老张的困境不是个例，是一代人的处境。2025年中国互联网裁员的不是几百人，是几十万人。每个被裁的人背后都有一个老张式的问题：<strong>接下来怎么办？</strong></p><p>这个故事的情绪共鸣点是跨年龄、跨阶层的：<strong>被时代抛下的无力感，和在一碗面里重新找到自己的可能性。</strong></p><h2 id="故事结构" tabindex="-1">故事结构 <a class="header-anchor" href="#故事结构" aria-label="Permalink to &quot;故事结构&quot;">​</a></h2><p>三幕，14集/章。每集5000-8000字，总计约8-12万字。</p><h3 id="第一幕-回来-第1-4集" tabindex="-1">第一幕：回来（第1-4集） <a class="header-anchor" href="#第一幕-回来-第1-4集" aria-label="Permalink to &quot;第一幕：回来（第1-4集）&quot;">​</a></h3><p>老张从北京回到县城，落差、冲突、格格不入。</p><table tabindex="0"><thead><tr><th>集</th><th>标题</th><th>核心事件</th></tr></thead><tbody><tr><td>1</td><td>体面人</td><td>老张被裁，回县城的决定</td></tr><tr><td>2</td><td>老城</td><td>回到餐馆，老城的萧条与新城的割裂</td></tr><tr><td>3</td><td>两个张建</td><td>兄弟冲突爆发——&quot;你在北京混不下去才回来摘桃子&quot;</td></tr><tr><td>4</td><td>第一顿饭</td><td>老张学做菜，开始理解食物和手艺</td></tr></tbody></table><h3 id="第二幕-折腾-第5-10集" tabindex="-1">第二幕：折腾（第5-10集） <a class="header-anchor" href="#第二幕-折腾-第5-10集" aria-label="Permalink to &quot;第二幕：折腾（第5-10集）&quot;">​</a></h3><p>老张试图用各种方式救活餐馆，碰壁、荒诞、渐渐理解县城的逻辑。</p><table tabindex="0"><thead><tr><th>集</th><th>标题</th><th>核心事件</th></tr></thead><tbody><tr><td>5</td><td>互联网思维</td><td>上外卖、搞营销，互联网打法在县城全面碰壁</td></tr><tr><td>6</td><td>左邻右舍</td><td>预制菜馆开张，传统餐饮的生死题</td></tr><tr><td>7</td><td>直播风波</td><td>直播翻车，意外发现&quot;真实&quot;比包装有用</td></tr><tr><td>8</td><td>拆迁风声</td><td>老城区可能要拆，餐馆面临存亡</td></tr><tr><td>9</td><td>儿子来了</td><td>12岁的儿子暑假来县城，最柔软也最扎心</td></tr><tr><td>10</td><td>最难的一天</td><td>所有压力集中爆发。老父亲深夜的一段话成为全书锚点</td></tr></tbody></table><h3 id="第三幕-扎根-第11-14集" tabindex="-1">第三幕：扎根（第11-14集） <a class="header-anchor" href="#第三幕-扎根-第11-14集" aria-label="Permalink to &quot;第三幕：扎根（第11-14集）&quot;">​</a></h3><p>老张不再想&quot;回北京&quot;，和父亲、弟弟、自己和解。</p><table tabindex="0"><thead><tr><th>集</th><th>标题</th><th>核心事件</th></tr></thead><tbody><tr><td>11</td><td>老街的味道</td><td>老街联合夜市，社区自发营造</td></tr><tr><td>12</td><td>和解</td><td>父子、兄弟、夫妻——三条线的和解</td></tr><tr><td>13</td><td>新的一天</td><td>餐馆站稳了。&quot;尝尝，这个AI做不了&quot;</td></tr><tr><td>14</td><td>老张餐馆</td><td>&quot;张记面馆&quot;改名&quot;老张餐馆&quot;。新招牌，新的一天</td></tr></tbody></table><h2 id="ip路线图与执行计划" tabindex="-1">IP路线图与执行计划 <a class="header-anchor" href="#ip路线图与执行计划" aria-label="Permalink to &quot;IP路线图与执行计划&quot;">​</a></h2><h3 id="第一阶段-连载小说-进行中" tabindex="-1">第一阶段：连载小说（进行中） <a class="header-anchor" href="#第一阶段-连载小说-进行中" aria-label="Permalink to &quot;第一阶段：连载小说（进行中）&quot;">​</a></h3><p>以网络连载的形式发布，每周1-2集，持续7-10周。</p><ul><li><strong>平台</strong>：自建网站（<a href="https://story.fangs.cc/novels/lao-zhang-restaurant/" target="_blank" rel="noreferrer">story.fangs.cc</a>）+ 社交平台同步分发</li><li><strong>制作方式</strong>：AI辅助创作——用AI做初稿，人工打磨调性和细节</li><li><strong>目标</strong>：跑通故事，验证共鸣点，积累种子读者</li></ul><h3 id="第二阶段-剧本改编" tabindex="-1">第二阶段：剧本改编 <a class="header-anchor" href="#第二阶段-剧本改编" aria-label="Permalink to &quot;第二阶段：剧本改编&quot;">​</a></h3><p>在小说完成后，将14集小说改编为短剧剧本。</p><ul><li><strong>形态</strong>：竖屏短剧，每集3-5分钟，14-20集</li><li><strong>改编重点</strong>：强化视觉场景（厨房、老街、县城）、强化节奏（每集结尾留钩子）、增加Fleabag式内心独白/对镜头说话</li><li><strong>可选</strong>：提取核心片段做成&quot;剧本杀&quot;或互动叙事</li></ul><h3 id="第三阶段-短剧制作" tabindex="-1">第三阶段：短剧制作 <a class="header-anchor" href="#第三阶段-短剧制作" aria-label="Permalink to &quot;第三阶段：短剧制作&quot;">​</a></h3><ul><li>低成本实拍或AI辅助影像生成</li><li>餐馆作为核心场景，制作门槛相对低</li><li>天然适合竖屏短剧的固定场景+群像叙事</li></ul><h3 id="长线ip可能性" tabindex="-1">长线IP可能性 <a class="header-anchor" href="#长线ip可能性" aria-label="Permalink to &quot;长线IP可能性&quot;">​</a></h3><ul><li><strong>&quot;老张&quot;可以成为一个符号</strong>——中国版的&quot;Walter White走进厨房&quot;，只不过他做的不是毒品，是牛肉面</li><li>餐馆是天然的延展场景：可以无限引入新人物、新故事、新社会议题</li><li>周边可能性：老张的菜谱、老街文创、播客/音频剧</li></ul><h2 id="为什么我们能做成" tabindex="-1">为什么我们能做成 <a class="header-anchor" href="#为什么我们能做成" aria-label="Permalink to &quot;为什么我们能做成&quot;">​</a></h2><p><strong>故事足够真实。</strong> 这不是凭空想象的题材——AI裁员、县城割裂、中年危机，每一个都是正在发生的事。真实是最大的竞争力。</p><p><strong>AI辅助创作降低制作门槛。</strong> 用AI写初稿、做分镜、生成视觉概念，让一个小团队也能产出精品级内容。这本身就和老张的故事形成了一种有趣的呼应——AI夺走了老张的工作，也在帮我们讲述老张的故事。</p><p><strong>小切口的连载模式天然适合传播。</strong> 每一集独立成章又互相关联，每个社会切面都是一个传播节点。&quot;老张遇到外卖平台&quot;这一集，所有被平台抽成压过的小商户都会转发。</p><p><strong>餐馆是最好的叙事容器。</strong> 人人都吃饭，人人都进过小餐馆。这个场景没有门槛，但有无限的故事空间。</p><hr><h2 id="核心团队" tabindex="-1">核心团队 <a class="header-anchor" href="#核心团队" aria-label="Permalink to &quot;核心团队&quot;">​</a></h2><p><strong>方 (Fangs)</strong> — 创作者 / 制片</p><p>AI从业者，理解技术也理解故事。《老张餐馆》的灵感来自于对身边人真实处境的观察——当AI开始替代我们自己的同行，这个故事就不再是假设，而是现实。</p><hr><blockquote><p><em>&quot;做餐馆的，最重要的一件事：明天还开门。&quot;</em></p><p>—— 老老张</p></blockquote><br><p><strong>项目主页</strong>：<a href="https://story.fangs.cc/novels/lao-zhang-restaurant/" target="_blank" rel="noreferrer">story.fangs.cc/novels/lao-zhang-restaurant</a></p><p><strong>故事大纲</strong>：<a href="/novels/lao-zhang-restaurant/behind-the-scenes/outline.html">完整大纲</a></p>',78)])])}const g=a(e,[["render",l]]);export{q as __pageData,g as default};
